from __future__ import annotations
import json
import logging
import os
import time
import uuid
from contextlib import contextmanager
from dataclasses import dataclass, field, asdict
from datetime import datetime
from typing import Any, Optional
from openai import OpenAI

log = logging.getLogger(__name__)
client = OpenAI(api_key=os.environ['OPENAI_API_KEY'])


# ── Span model ─────────────────────────────────────────────────────────────────

@dataclass
class Span:
    span_id: str = field(default_factory=lambda: str(uuid.uuid4())[:8])
    parent_id: Optional[str] = None
    span_type: str = 'unknown'  # llm | tool | agent | retrieval
    name: str = ''
    inputs: dict = field(default_factory=dict)
    outputs: dict = field(default_factory=dict)
    start_time: float = field(default_factory=time.time)
    end_time: Optional[float] = None
    model: Optional[str] = None
    input_tokens: int = 0
    output_tokens: int = 0
    cost_usd: float = 0.0
    error: Optional[str] = None
    metadata: dict = field(default_factory=dict)

    @property
    def duration_ms(self) -> float:
        if self.end_time:
            return (self.end_time - self.start_time) * 1000
        return 0.0

    def finish(self, outputs: dict = None, error: str = None) -> None:
        self.end_time = time.time()
        if outputs:
            self.outputs = outputs
        if error:
            self.error = error


# ── Trace (collection of spans) ────────────────────────────────────────────────

@dataclass
class Trace:
    trace_id: str = field(default_factory=lambda: str(uuid.uuid4())[:12])
    task: str = ''
    spans: list[Span] = field(default_factory=list)
    start_time: float = field(default_factory=time.time)
    end_time: Optional[float] = None
    success: bool = True
    metadata: dict = field(default_factory=dict)

    def add_span(self, span: Span) -> None:
        self.spans.append(span)

    def finish(self, success: bool = True) -> None:
        self.end_time = time.time()
        self.success = success

    @property
    def total_duration_ms(self) -> float:
        return (self.end_time - self.start_time) * 1000 if self.end_time else 0.0

    @property
    def total_cost_usd(self) -> float:
        return sum(s.cost_usd for s in self.spans)

    @property
    def total_tokens(self) -> int:
        return sum(s.input_tokens + s.output_tokens for s in self.spans)

    def summary(self) -> dict:
        return {
            'trace_id': self.trace_id,
            'task': self.task[:80],
            'duration_ms': round(self.total_duration_ms),
            'total_tokens': self.total_tokens,
            'total_cost_usd': round(self.total_cost_usd, 5),
            'n_spans': len(self.spans),
            'n_llm_calls': sum(1 for s in self.spans if s.span_type == 'llm'),
            'n_tool_calls': sum(1 for s in self.spans if s.span_type == 'tool'),
            'errors': [s.error for s in self.spans if s.error],
            'success': self.success,
        }


# ── Tracer ─────────────────────────────────────────────────────────────────────

class AgentTracer:
    # GPT-4o-mini pricing (per 1K tokens)
    COST_TABLE = {
        'gpt-4o-mini': {'input': 0.00015, 'output': 0.00060},
        'gpt-4o': {'input': 0.0025, 'output': 0.01},
    }

    def __init__(self, export_fn=None):
        self._current_trace: Optional[Trace] = None
        self._export_fn = export_fn or self._log_trace

    @contextmanager
    def trace(self, task: str, **metadata):
        self._current_trace = Trace(task=task, metadata=metadata)
        try:
            yield self._current_trace
            self._current_trace.finish(success=True)
        except Exception as e:
            if self._current_trace:
                self._current_trace.finish(success=False)
                self._current_trace.metadata['error'] = str(e)
            raise
        finally:
            if self._current_trace:
                self._export_fn(self._current_trace)

    @contextmanager
    def span(self, name: str, span_type: str, **kwargs):
        parent_id = self._current_trace.spans[-1].span_id if self._current_trace and self._current_trace.spans else None
        s = Span(span_type=span_type, name=name, parent_id=parent_id, metadata=kwargs)
        try:
            yield s
        except Exception as e:
            s.finish(error=str(e))
            raise
        finally:
            if not s.end_time:
                s.finish()
            if self._current_trace:
                self._current_trace.add_span(s)

    def traced_llm_call(
        self,
        messages: list[dict],
        model: str = 'gpt-4o-mini',
        tools: Optional[list] = None,
        **kwargs,
    ):
        with self.span(f'LLM:{model}', 'llm') as span:
            span.model = model
            span.inputs = {'messages_count': len(messages), 'has_tools': bool(tools)}

            response = client.chat.completions.create(
                model=model,
                messages=messages,
                tools=tools or [],
                **kwargs,
            ) if tools else client.chat.completions.create(
                model=model,
                messages=messages,
                **kwargs,
            )

            usage = response.usage
            span.input_tokens = usage.prompt_tokens
            span.output_tokens = usage.completion_tokens

            costs = self.COST_TABLE.get(model, {'input': 0, 'output': 0})
            span.cost_usd = (
                usage.prompt_tokens / 1000 * costs['input'] +
                usage.completion_tokens / 1000 * costs['output']
            )
            span.outputs = {'finish_reason': response.choices[0].finish_reason}
            span.finish()
            return response

    def traced_tool_call(
        self,
        tool_name: str,
        tool_args: dict,
        tool_fn,
    ) -> str:
        with self.span(f'Tool:{tool_name}', 'tool') as span:
            span.inputs = tool_args
            try:
                result = tool_fn(**tool_args)
                result_str = json.dumps(result) if not isinstance(result, str) else result
                span.finish(outputs={'result_length': len(result_str)})
                return result_str
            except Exception as e:
                span.finish(error=str(e))
                return json.dumps({'error': str(e)})

    def _log_trace(self, trace: Trace) -> None:
        summary = trace.summary()
        level = logging.ERROR if not trace.success else logging.INFO
        log.log(level, 'TRACE: %s', json.dumps(summary))
        # In production: send to Langfuse, DataDog, or your observability backend


# ── LangSmith integration (when using LangChain) ──────────────────────────────

def setup_langsmith(project_name: str) -> None:
    """Configure LangSmith tracing for all LangChain calls."""
    if not os.environ.get('LANGCHAIN_API_KEY'):
        log.warning('LANGCHAIN_API_KEY not set — LangSmith tracing disabled')
        return
    os.environ['LANGCHAIN_TRACING_V2'] = 'true'
    os.environ['LANGCHAIN_PROJECT'] = project_name
    log.info('LangSmith tracing enabled for project: %s', project_name)


