# ── Trace-enabled agent ───────────────────────────────────────────────────────

tracer = AgentTracer()


def get_weather(city: str) -> str:
    return json.dumps({'city': city, 'temp': '20°C', 'condition': 'sunny'})

def calculate(expression: str) -> str:
    try:
        result = eval(expression, {'__builtins__': {}})  # noqa: S307
        return json.dumps({'result': result})
    except Exception as e:
        return json.dumps({'error': str(e)})

TOOL_REGISTRY = {'get_weather': get_weather, 'calculate': calculate}

TOOLS = [
    {'type': 'function', 'function': {
        'name': 'get_weather', 'description': 'Get weather for a city',
        'parameters': {'type': 'object', 'properties': {'city': {'type': 'string'}}, 'required': ['city']}
    }},
    {'type': 'function', 'function': {
        'name': 'calculate', 'description': 'Evaluate a math expression',
        'parameters': {'type': 'object', 'properties': {'expression': {'type': 'string'}}, 'required': ['expression']}
    }},
]


def traced_agent(task: str) -> str:
    with tracer.trace(task=task) as trace:
        messages = [{'role': 'user', 'content': task}]

        for _ in range(5):
            response = tracer.traced_llm_call(messages, model='gpt-4o-mini', tools=TOOLS)
            msg = response.choices[0].message
            messages.append(msg)

            if not msg.tool_calls:
                return msg.content

            for tc in msg.tool_calls:
                args = json.loads(tc.function.arguments)
                result = tracer.traced_tool_call(
                    tc.function.name, args, TOOL_REGISTRY[tc.function.name]
                )
                messages.append({'role': 'tool', 'tool_call_id': tc.id, 'content': result})

        return 'Max rounds'


# ── Demo ──────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    logging.basicConfig(level=logging.INFO, format='%(levelname)s %(message)s')

    tasks = [
        'What is the weather in Tokyo and what is 18 * 24?',
        'Calculate the sum of squares from 1 to 5 and check weather in Paris',
    ]

    for task in tasks:
        print(f'\n--- Task: {task} ---')
        result = traced_agent(task)
        print(f'Result: {result}')

